/**
 * 管理端接口：独立 Token，与会员微信登录无关
 */
import { getApiBase } from './request.js';

export const ADMIN_TOKEN_KEY = 'adminToken';

export function getAdminToken() {
	try {
		return uni.getStorageSync(ADMIN_TOKEN_KEY) || '';
	} catch {
		return '';
	}
}

export function setAdminToken(token) {
	uni.setStorageSync(ADMIN_TOKEN_KEY, token);
}

export function clearAdminToken() {
	try {
		uni.removeStorageSync(ADMIN_TOKEN_KEY);
	} catch (_) {}
}

/** 管理员账号密码登录 → 后端签发 JWT */
export function adminLogin(username, password) {
	return new Promise((resolve, reject) => {
		uni.request({
			url: getApiBase() + '/api/admin/auth/login',
			method: 'POST',
			header: {
				'Content-Type': 'application/json',
				'source-client': 'miniapp',
			},
			data: { username: String(username || '').trim(), password: String(password || '') },
			timeout: 15000,
			success: (res) => {
				if (res.statusCode >= 200 && res.statusCode < 300 && res.data && res.data.token) {
					setAdminToken(res.data.token);
					resolve(res.data);
				} else {
					reject(new Error((res.data && res.data.message) || '登录失败'));
				}
			},
			fail: (err) => reject(new Error(err.errMsg || '网络错误')),
		});
	});
}

/** 带管理员 Bearer Token 的请求（后续商品 CRUD、上传等均用此封装） */
export function adminRequest(options) {
	const token = getAdminToken();
	const url =
		options.url && options.url.startsWith('http')
			? options.url
			: getApiBase() + (options.url || '');
	return new Promise((resolve, reject) => {
		uni.request({
			...options,
			url,
			header: {
				'Content-Type': 'application/json',
				'source-client': 'miniapp',
				...(token ? { Authorization: `Bearer ${token}` } : {}),
				...options.header,
			},
			timeout: options.timeout || 15000,
			success: (res) => {
				if (res.statusCode === 401) {
					clearAdminToken();
					uni.showToast({ title: '登录已失效', icon: 'none' });
					uni.redirectTo({ url: '/pages/admin/login' });
					reject(new Error((res.data && res.data.message) || '401'));
					return;
				}
				if (res.statusCode >= 200 && res.statusCode < 300) {
					resolve(res.data);
				} else {
					reject(new Error((res.data && res.data.message) || `请求失败 (${res.statusCode})`));
				}
			},
			fail: (err) => reject(new Error(err.errMsg || '网络错误')),
		});
	});
}

export function adminAuthVerify() {
	return adminRequest({ url: '/api/admin/auth/verify', method: 'GET' });
}

export function adminPing() {
	return adminRequest({ url: '/api/admin/ping', method: 'GET' });
}

export function adminGetProducts(query) {
	const q =
		query && query.categoryId != null && query.categoryId !== ''
			? `?categoryId=${encodeURIComponent(query.categoryId)}`
			: '';
	return adminRequest({ url: '/api/admin/products' + q, method: 'GET' });
}
